final:
module RefModule(
    input [7:0] data,
    input clk,
    input rst,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= data;
    end

endmodule
